import { Router } from "express";
import tarjetasController from "../controllers/tarjetas.controller.js";
import { validateBody } from "../middleware/validate.middleware.js";
import { createTarjetaSchema, updateTarjetaSchema } from "../validators/tarjetas.validator.js";
const router = Router();
router.get("/", tarjetasController.getList);
router.get("/:id", tarjetasController.getById);
router.post("/", validateBody(createTarjetaSchema), tarjetasController.create);
router.patch("/:id", validateBody(updateTarjetaSchema), tarjetasController.update);
router.delete("/:id", tarjetasController.delete);
export default router;
